    if not data:
        return []
    min_val = min(data)
    max_val = max(data)
    bin_width = (max_val - min_val) / bins
    histogram = [0] * bins
    for value in data:
        if value == max_val:
            bin_index = bins - 1
        else:
            bin_index = int((value - min_val) / bin_width)
        if 0 <= bin_index < bins:
            histogram[bin_index] += 1
    return histogram

